ttps://api.github.com/repos/bokeh/bokeh/labels/TRIAGE","name":"TRIAGE","color":"e2e2e2","default":false,"description":""}],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":0,"created_at":"2024-05-07T11:58:57Z","updated_at":"2024-05-07T11:58:58Z","closed_at":null,"author_association":"CONTRIBUTOR","active_lock_reason":null,"body":"The `circle` renderer of bokehjs doesn't fiend the fields `x` and `y`.

The example below

```javascript
// create a data source to hold data
const source = new Bokeh.ColumnDataSource({
    data: { x: [1,2,3], y: [1,2,3] }
});

// make a plot with some tools
const plot = Bokeh.Plotting.figure({
    title: 'Example of random data',
    tools: "pan,wheel_zoom,box_zoom,reset,save",
    height: 300,
    width: 300
});

// add a line with data from the source
plot.circle({ field: "x" }, { field: "y" }, {
    source: source,
    line_width: 2
});

// show the plot, appending it to the end of the current section
Bokeh.Plotting.show(plot);
```

produces warnings in the browser console.

```
"[bokeh 3.4.1]" "attempted to retrieve property array for nonexistent field 'x'"
"[bokeh 3.4.1]" "attempted to retrieve property array for nonexistent field 'y'"
